var userConnection = Get<UserConnection>("UserConnection");
var commonInventoryService = new CommonInventoryService(userConnection);
Guid lineDetailId = Get<Guid>("LineDetailId");

try {
    var reserve = commonInventoryService.Reserve(lineDetailId).GetAwaiter().GetResult();
    string reservationId = reserve.ReservationID;

    Set("reservationId", reservationId);    
    Set("Result", JsonConvert.SerializeObject(reserve.Response, Formatting.Indented));
} catch(Exception e) {
    Set("Result", e.Message);
}

return true;
